You can achieve this by using the `HttpClient` class in ASP.NET Core to make a request to the target endpoint and then return the response to the client. Here's an example of how you can implement a proxy controller:

```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient();
    }

    [HttpGet]
    [Route("{proxyPath}")]
    public async Task<IActionResult> Proxy([FromRoute] string proxyPath)
    {
        var request = new HttpRequestMessage(HttpMethod.Get, proxyPath);
        var response = await _httpClient.SendAsync(request);

        response.EnsureSuccessStatusCode();

        return new ObjectResult(await response.Content.ReadAsStringAsync())
        {
            StatusCode = (int)response.StatusCode
        };
    }
}
```

